using System;
using System.ComponentModel;
using System.Runtime.CompilerServices;
using System.Threading;
using System.Threading.Tasks;
using example-project.Application.Accounting;
using example-project.Application.Common;
using example-project.Application.Security;
using example-project.App.Infrastructure;
using example-project.App.Shared;
using example-project.App.Security;

namespace example-project.App.Accounting.Accounts;

public sealed class AccountPeekViewModel : INotifyPropertyChanged
{
    private readonly IAccountDetailsService _detailsService;
    private readonly ICompanyContext _companyContext;
    private readonly IPermissionService _permissionService;
    private bool _isLoading;
    private string? _errorMessage;
    private string _number = string.Empty;
    private string _name = string.Empty;
    private string _typeDisplay = string.Empty;
    private string _roleDisplay = string.Empty;
    private string _systemFlagDisplay = string.Empty;
    private Guid? _currentAccountId;
    private readonly SafeCommand _openLedgerMappingsCommand;

    public AccountPeekViewModel(
        IAccountDetailsService detailsService,
        ICompanyContext companyContext,
        IPermissionService permissionService)
    {
        ArgumentNullException.ThrowIfNull(detailsService);
        ArgumentNullException.ThrowIfNull(companyContext);
        ArgumentNullException.ThrowIfNull(permissionService);

        _detailsService = detailsService;
        _companyContext = companyContext;
        _permissionService = permissionService;
        _openLedgerMappingsCommand = new SafeCommand(
            "AccountPeek.OpenLedgerMappings",
            RequestOpenLedgerMappings,
            () => CanOpenLedgerMappings && _currentAccountId.HasValue,
            actionLabel: "open ledger mappings");
    }

    public event PropertyChangedEventHandler? PropertyChanged;
    public event EventHandler<Guid>? OpenLedgerMappingsRequested;

    public bool IsLoading
    {
        get => _isLoading;
        private set => SetProperty(ref _isLoading, value);
    }

    public string? ErrorMessage
    {
        get => _errorMessage;
        private set
        {
            if (SetProperty(ref _errorMessage, value))
            {
                OnPropertyChanged(nameof(HasError));
            }
        }
    }

    public bool HasError => !string.IsNullOrWhiteSpace(ErrorMessage);

    public string Number
    {
        get => _number;
        private set => SetProperty(ref _number, value);
    }

    public string Name
    {
        get => _name;
        private set => SetProperty(ref _name, value);
    }

    public string TypeDisplay
    {
        get => _typeDisplay;
        private set => SetProperty(ref _typeDisplay, value);
    }

    public string RoleDisplay
    {
        get => _roleDisplay;
        private set => SetProperty(ref _roleDisplay, value);
    }

    public string SystemFlagDisplay
    {
        get => _systemFlagDisplay;
        private set => SetProperty(ref _systemFlagDisplay, value);
    }

    public bool CanOpenLedgerMappings => _permissionService.HasPermission(PermissionCodes.AccountsView);

    public SafeCommand OpenLedgerMappingsCommand => _openLedgerMappingsCommand;

    public async Task LoadAsync(Guid accountId, CancellationToken cancellationToken = default)
    {
        IsLoading = true;
        ErrorMessage = null;

        try
        {
            var companyId = await _companyContext.GetCurrentCompanyIdAsync(cancellationToken).ConfigureAwait(true);
            if (!companyId.HasValue)
            {
                ClearDetails();
                ErrorMessage = "Select a company before opening account details.";
                return;
            }

            var dto = await _detailsService.GetAsync(companyId.Value, accountId, cancellationToken).ConfigureAwait(true);
            if (dto is null)
            {
                ClearDetails();
                ErrorMessage = "Account could not be found for the active company.";
                return;
            }

            _currentAccountId = dto.Id;
            Number = dto.Number;
            Name = dto.Name;
            TypeDisplay = dto.Type.ToString();
            RoleDisplay = dto.Role.ToString();
            SystemFlagDisplay = dto.IsSystem ? "System Account" : "Custom Account";
            _openLedgerMappingsCommand.RaiseCanExecuteChanged();
        }
        catch (OperationCanceledException)
        {
        }
        catch (Exception ex)
        {
            ClearDetails();
            ErrorMessage = ex.Message;
        }
        finally
        {
            IsLoading = false;
        }
    }

    private void ClearDetails()
    {
        _currentAccountId = null;
        Number = string.Empty;
        Name = string.Empty;
        TypeDisplay = string.Empty;
        RoleDisplay = string.Empty;
        SystemFlagDisplay = string.Empty;
        _openLedgerMappingsCommand.RaiseCanExecuteChanged();
    }

    private void RequestOpenLedgerMappings()
    {
        if (_currentAccountId.HasValue && CanOpenLedgerMappings)
        {
            OpenLedgerMappingsRequested?.Invoke(this, _currentAccountId.Value);
        }
    }

    private bool SetProperty<T>(ref T field, T value, [CallerMemberName] string? propertyName = null)
    {
        if (Equals(field, value))
        {
            return false;
        }

        field = value;
        OnPropertyChanged(propertyName);
        return true;
    }

    private void OnPropertyChanged(string? propertyName) =>
        PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(propertyName));
}

